/**
 * Storage shim for artifact viewer.
 *
 * This script is injected as the first <head> element before any artifact
 * scripts run. It intercepts localStorage and sessionStorage, hydrating
 * state from the server once on load and writing through asynchronously
 * on every setItem call.
 *
 * This file is bundled by esbuild for production use. The inline version
 * is generated by internal/render/render.go via shimTemplate.
 */

(function () {
  var ARTIFACT_ID = window.__ARTIFACT_ID__ || '';
  var API_ORIGIN = window.__API_ORIGIN__ || '';

  if (!ARTIFACT_ID || !API_ORIGIN) {
    return; // not in artifact context
  }

  /** @type {Record<string, string>} */
  var cache = {};
  var hydrated = false;

  // Hydrate state from server
  fetch(API_ORIGIN + '/api/artifacts/' + ARTIFACT_ID + '/state', {
    headers: { 'Content-Type': 'application/json' },
  })
    .then(function (r) {
      return r.ok ? r.json() : {};
    })
    .then(function (state) {
      cache = state || {};
      hydrated = true;
    })
    .catch(function () {
      hydrated = true;
    });

  /**
   * Write a key/value pair through to the API asynchronously.
   * @param {string} key
   * @param {string} value
   */
  function writeThrough(key, value) {
    fetch(API_ORIGIN + '/api/artifacts/' + ARTIFACT_ID + '/state', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ key: key, value: value }),
    }).catch(function () {});
  }

  /** @type {Storage} */
  var shimStorage = {
    getItem: function (key) {
      return Object.prototype.hasOwnProperty.call(cache, key)
        ? cache[key]
        : null;
    },
    setItem: function (key, value) {
      cache[key] = String(value);
      writeThrough(key, String(value));
    },
    removeItem: function (key) {
      delete cache[key];
      writeThrough(key, '');
    },
    clear: function () {
      cache = {};
    },
    key: function (n) {
      return Object.keys(cache)[n] || null;
    },
    get length() {
      return Object.keys(cache).length;
    },
  };

  try {
    Object.defineProperty(window, 'localStorage', {
      value: shimStorage,
      writable: false,
    });
    Object.defineProperty(window, 'sessionStorage', {
      value: shimStorage,
      writable: false,
    });
  } catch (e) {
    // Some browsers disallow redefining window.localStorage
  }
})();
